 using System.Text.Json;
 using System.Text.Json.Serialization.Metadata;

 var options = new JsonSerializerOptions
 {
     TypeInfoResolver = new DefaultJsonTypeInfoResolver()
 };

 // 1) Strongly-typed retrieval — returns JsonTypeInfo<Person> directly
 JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
 Console.WriteLine($"Got typed metadata for: {personInfo.Type.Name}");

 // 2) Probe without throwing — TryGetTypeInfo returns false if unavailable
 if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? probed))
     Console.WriteLine($"TryGetTypeInfo succeeded for {probed!.Type.Name}");

 // Try a type whose resolver returns null (simulates "metadata not available")
 var limited = new JsonSerializerOptions
 {
     TypeInfoResolver = JsonTypeInfoResolver.Combine(
         // A resolver that only knows about Person, not Order
         new DefaultJsonTypeInfoResolver
         {
             Modifiers = { ti => { if (ti.Type != typeof(Person)) ti.MakeReadOnly(); } }
         })
 };

 // Actually, the simplest demo: use a source-gen context that only covers Person.
 // Instead, just use an empty IJsonTypeInfoResolver:
 var empty = new JsonSerializerOptions
 {
     TypeInfoResolver = JsonTypeInfoResolver.Combine() // resolves nothing
 };

 if (!empty.TryGetTypeInfo(typeof(Order), out _))
     Console.WriteLine("TryGetTypeInfo correctly returned false for Order (no resolver covers it)");

 record Person(string Name, int Age);
 record Order(int Id);
